import os
import requests
import time

API_KEY = "123"  # Tu free API Key de demo
LEAGUES = [
    "LaLiga EA Sports",
    "Premier League",
    "Serie A",
    "Bundesliga",
    "Ligue 1",
    "Eredivisie",
    "Primeira Liga",
    "Liga Profesional Argentina",
    "Brasileirão Serie A"
]

# Función para descargar imágenes
def download_image(url, path):
    if url and url != "":
        try:
            img_data = requests.get(url).content
            os.makedirs(os.path.dirname(path), exist_ok=True)
            with open(path, "wb") as f:
                f.write(img_data)
            print("Descargado:", path)
        except Exception as e:
            print("Error descargando", url, ":", e)

# Obtener equipos de una liga
def get_teams_by_league(league_name):
    url = f"https://www.thesportsdb.com/api/v1/json/{API_KEY}/search_all_teams.php?l={league_name}"
    response = requests.get(url).json()
    teams = response.get("teams")
    if teams:
        return teams
    else:
        print(f"No se encontraron equipos para la liga: {league_name}")
        return []

# Descargar imágenes de un equipo y sus jugadores
def download_team_images(team):
    team_name = team.get("strTeam")
    team_id = team.get("idTeam")
    if not team_name or not team_id:
        return

    # Escudos del equipo
    download_image(team.get("strTeamBadge"), f"./teams/{team_name}/badge.png")
    download_image(team.get("strTeamLogo"), f"./teams/{team_name}/logo.png")

    # Jugadores del equipo
    players_url = f"https://www.thesportsdb.com/api/v1/json/{API_KEY}/lookup_all_players.php?id={team_id}"
    try:
        players = requests.get(players_url).json().get("player", [])
    except:
        players = []

    for p in players:
        pname = p.get("strPlayer")
        if pname:
            pname_safe = pname.replace(" ", "_").replace("/", "_")
            download_image(p.get("strCutout"), f"./teams/{team_name}/players/{pname_safe}_cutout.png")
            download_image(p.get("strThumb"), f"./teams/{team_name}/players/{pname_safe}_thumb.jpg")

# Bucle principal
for league in LEAGUES:
    print("\n=== Descargando equipos de la liga:", league, "===")
    teams = get_teams_by_league(league)
    for team in teams:
        print("\nDescargando imágenes del equipo:", team.get("strTeam"))
        download_team_images(team)
        time.sleep(1)  # Pausa de 1 segundo para no sobrecargar la API

print("\n¡Descarga finalizada!")
